#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
#[repr(transparent)]
pub struct AggregateFunctionCallFlags(pub u8);

impl AggregateFunctionCallFlags {
    pub fn distinct(&self) -> bool {
        self.0 & 1 != 0
    }

    pub fn dump_str(&self) -> String {
        if self.0 == 0 {
            return "(none)".into();
        }
        let mut s = String::new();
        if self.distinct() {
            if !s.is_empty() {
                s.push(' ');
            }
            s.push_str("DISTINCT");
        }
        s
    }
}

